     index += 1;
   }

   return parsed;
 }

 function mimeToExtension(mimeType) {
   switch (mimeType) {
     case "image/jpeg":
       return ".jpg";
     case "image/webp":
       return ".webp";
     default:
       return ".png";
   }
 }

 async function main() {
   const args = parseArgs(process.argv.slice(2));

   if (args.help) {
     printUsage();
     process.exit(0);
   }

   const prompt = String(args.prompt ?? "").trim();
   if (!prompt) {
     printUsage();
     throw new Error("缺少 --prompt。");
